import React from 'react';
import { FetchMachine } from './FetchMachine';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '28rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>State Machine</h1>
      <FetchMachine />
    </div>
  );
}

import React from 'react';
import { useMachine, MachineConfig } from './useMachine';
import './styles.css';

interface FetchContext {
  data: string | null;
  error: string | null;
  retryCount: number;
}

const fetchMachineConfig: MachineConfig<FetchContext> = {
  states: {
    idle: {
      on: {
        FETCH: { target: 'loading' },
      },
    },
    loading: {
      on: {
        RESOLVE: {
          target: 'success',
          assign: (ctx, event) => ({ ...ctx, data: event.data ?? 'Response data' }),
        },
        REJECT: {
          target: 'error',
          assign: (ctx, event) => ({
            ...ctx,
            error: event.error ?? 'Something went wrong',
            retryCount: ctx.retryCount + 1,
          }),
        },
      },
    },
    success: {
      on: {
        RESET: {
          target: 'idle',
          assign: (ctx) => ({ ...ctx, data: null }),
        },
      },
    },
    error: {
      on: {
        RETRY: {
          target: 'loading',
          guard: (ctx) => ctx.retryCount < 3,
        },
        RESET: {
          target: 'idle',
          assign: (ctx) => ({ ...ctx, error: null, retryCount: 0 }),
        },
      },
    },
  },
};

const initialContext: FetchContext = { data: null, error: null, retryCount: 0 };

export const FetchMachine: React.FC = () => {
  const { state, context, send } = useMachine(fetchMachineConfig, 'idle', initialContext);

  return (
    <div className="machine">
      <div className="machine__state">
        <span className="machine__label">State:</span>
        <span data-testid="current-state" className={`machine__badge machine__badge--${state}`}>{state}</span>
      </div>

      <div className="machine__info">
        {context.data && <p data-testid="data-display" className="machine__data">Data: {context.data}</p>}
        {context.error && <p data-testid="error-display" className="machine__error">Error: {context.error}</p>}
        <p data-testid="retry-count" className="machine__retry">Retries: {context.retryCount}/3</p>
      </div>

      <div className="machine__actions">
        <button data-testid="fetch-btn" className="btn" onClick={() => send({ type: 'FETCH' })} disabled={state !== 'idle'}>Fetch</button>
        <button data-testid="resolve-btn" className="btn btn--success" onClick={() => send({ type: 'RESOLVE', data: 'Hello World' })} disabled={state !== 'loading'}>Resolve</button>
        <button data-testid="reject-btn" className="btn btn--error" onClick={() => send({ type: 'REJECT', error: 'Network error' })} disabled={state !== 'loading'}>Reject</button>
        <button data-testid="retry-btn" className="btn" onClick={() => send({ type: 'RETRY' })} disabled={state !== 'error' || context.retryCount >= 3}>Retry</button>
        <button data-testid="reset-btn" className="btn btn--ghost" onClick={() => send({ type: 'RESET' })} disabled={state === 'idle' || state === 'loading'}>Reset</button>
      </div>
    </div>
  );
};

