.machine {
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.machine__state {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.machine__label {
  font-size: 0.875rem;
  color: #6b7280;
}

.machine__badge {
