import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

describe('Finite State Machine', () => {
  function renderApp() {
    const App = require('./App').default;
    render(<App />);
  }

  it('starts in idle state', () => {
    renderApp();
    expect(screen.getByTestId('current-state')).toHaveTextContent('idle');
  });

  it('transitions to loading on FETCH', () => {
    renderApp();
    fireEvent.click(screen.getByTestId('fetch-btn'));
    expect(screen.getByTestId('current-state')).toHaveTextContent('loading');
  });

  it('transitions to success on RESOLVE', () => {
    renderApp();
    fireEvent.click(screen.getByTestId('fetch-btn'));
    fireEvent.click(screen.getByTestId('resolve-btn'));
    expect(screen.getByTestId('current-state')).toHaveTextContent('success');
    expect(screen.getByTestId('data-display')).toHaveTextContent('Hello World');
  });

  it('transitions to error on REJECT', () => {
    renderApp();
    fireEvent.click(screen.getByTestId('fetch-btn'));
    fireEvent.click(screen.getByTestId('reject-btn'));
    expect(screen.getByTestId('current-state')).toHaveTextContent('error');
    expect(screen.getByTestId('error-display')).toHaveTextContent('Network error');
    expect(screen.getByTestId('retry-count')).toHaveTextContent('1/3');
  });

  it('allows retry from error up to 3 times', () => {
    renderApp();
    fireEvent.click(screen.getByTestId('fetch-btn'));
    fireEvent.click(screen.getByTestId('reject-btn'));
    fireEvent.click(screen.getByTestId('retry-btn'));
    expect(screen.getByTestId('current-state')).toHaveTextContent('loading');
  });

  it('blocks retry after 3 failures', () => {
    renderApp();
    for (let i = 0; i < 3; i++) {
      fireEvent.click(screen.getByTestId('fetch-btn').closest('button') || screen.getByTestId('retry-btn').closest('button') || document.body);
      if (screen.getByTestId('current-state').textContent === 'idle') {
        fireEvent.click(screen.getByTestId('fetch-btn'));
      }
      if (screen.getByTestId('current-state').textContent === 'error') {
        fireEvent.click(screen.getByTestId('retry-btn'));
      }
      if (screen.getByTestId('current-state').textContent === 'loading') {
        fireEvent.click(screen.getByTestId('reject-btn'));
      }
    }
    // After 3 rejections, retry count is 3 and retry should be blocked
    expect(screen.getByTestId('retry-count')).toHaveTextContent('3/3');
    expect(screen.getByTestId('retry-btn')).toBeDisabled();
  });

  it('resets from success to idle', () => {
    renderApp();
    fireEvent.click(screen.getByTestId('fetch-btn'));
    fireEvent.click(screen.getByTestId('resolve-btn'));
    fireEvent.click(screen.getByTestId('reset-btn'));
    expect(screen.getByTestId('current-state')).toHaveTextContent('idle');
  });

  it('ignores invalid transitions', () => {
    renderApp();
    // In idle, RESOLVE should have no effect
    fireEvent.click(screen.getByTestId('resolve-btn'));
    expect(screen.getByTestId('current-state')).toHaveTextContent('idle');
  });
});

