import { useReducer, useCallback } from 'react';

export interface MachineEvent {
  type: string;
  [key: string]: any;
}

export interface Transition<C> {
  target: string;
  assign?: (context: C, event: MachineEvent) => C;
  guard?: (context: C) => boolean;
}

export interface StateNode<C> {
  on: Record<string, Transition<C>>;
}

export interface MachineConfig<C> {
  states: Record<string, StateNode<C>>;
}

interface MachineState<C> {
  value: string;
  context: C;
}

function createMachineReducer<C>(config: MachineConfig<C>) {
  return (state: MachineState<C>, event: MachineEvent): MachineState<C> => {
    const stateNode = config.states[state.value];
    if (!stateNode) return state;

    const transition = stateNode.on[event.type];
    if (!transition) return state;

    // Check guard
    if (transition.guard && !transition.guard(state.context)) {
      return state;
    }

    // Apply assign to produce new context
    const nextContext = transition.assign
      ? transition.assign(state.context, event)
      : state.context;

    return { value: transition.target, context: nextContext };
  };
}

export function useMachine<C>(config: MachineConfig<C>, initialState: string, initialContext: C) {
  const reducer = createMachineReducer(config);
  const [machineState, dispatch] = useReducer(reducer, {
    value: initialState,
    context: initialContext,
  });

  const send = useCallback((event: MachineEvent) => {
    dispatch(event);
  }, []);

  return {
    state: machineState.value,
    context: machineState.context,
    send,
  };
}
